            ContentJson = """{"appRoute":"/customers","startButtonLabel":"Tour Creating a Customer","steps":[{"element":"[data-testid='new-customer-btn']","popover":{"title":"Start Here: + New Customer","description":"Click this button to start creating a customer. It does NOT open a form right away — first it opens a small window asking how you want to create the customer. Click it now to see the three choices.","side":"bottom"}},{"element":"[data-testid='customer-fork-quick']","popover":{"title":"Quick Add (Fastest)","description":"The highlighted, recommended choice. Opens a single form where only the Name is required. Pick this when you just need the record in the system now and will fill in details later. New customers start out active.","side":"bottom"}},{"element":"[data-testid='customer-fork-fromLead']","popover":{"title":"Convert from Lead","description":"Opens a lead picker. Search your existing leads, click one, and the system creates the customer in one step — linking the original lead and carrying its contacts over, with no retyping. Use this whenever a lead already exists.","side":"bottom"}},{"element":"[data-testid='customer-fork-guided']","popover":{"title":"Guided Setup","description":"Walks you through a step-by-step wizard: Identity, Addresses, Credit & Tax, and Review. Best for an important new account you want set up thoroughly. An Express switch collapses the steps into one screen.","side":"bottom"}}]}"""
